    async function loadAssets(){const params=new URLSearchParams({platform:state.tab,type:$('type-filter').value,published:$('published-filter').value,query:$('search').value,limit:String(state.limit),offset:String(state.offset),sort:state.sort,order:state.order});state.domainFilters.forEach(domain=>params.append('businessDomain',domain));const data=await api('/admin/api/assets?'+params);state.total=data.total;state.items=data.assets;const analysisHeader=state.tab==='posthog'?'<th>分析类型</th>':'';$('thead').innerHTML='<tr><th><input id="select-all" type="checkbox" aria-label="选择当前页" /></th><th class="sortable" data-sort="published">开放</th><th class="sortable" data-sort="title">元信息</th><th class="sortable" data-sort="type">类型</th>'+analysisHeader+'<th class="sortable" data-sort="business_domain">业务域</th><th class="sortable" data-sort="active">状态</th><th class="sortable" data-sort="last_synced_at">同步时间</th><th>操作</th></tr>';bindSortHeaders();setupResizableColumns('assets-'+state.tab,state.tab==='posthog'?[48,82,320,110,130,190,100,190,110]:[48,82,320,120,190,100,190,110]);bindSelectAll();$('tbody').replaceChildren(...data.assets.map(renderAssetRow));updatePager();updateBulkActions();}
    async function loadDomains(){const data=await api('/admin/api/domains?platform='+encodeURIComponent(state.tab));state.domains=data.summaries||data.domains.map(name=>({name,assetCount:0,publishedCount:0,status:'closed'}));const available=new Set(state.domains.map(domain=>domain.name));state.domainFilters.forEach(domain=>{if(!available.has(domain))state.domainFilters.delete(domain);});renderDomainFilter();renderDomainManager();}
