    function renderDomainFilter(){const query=$('domain-filter-search').value.trim().toLowerCase();const domains=state.domains.filter(domain=>!query||domain.name.toLowerCase().includes(query));const options=$('domain-filter-options');if(!domains.length){const empty=document.createElement('div');empty.className='permission-row muted';empty.textContent='没有匹配的业务域';options.replaceChildren(empty);}else{options.replaceChildren(...domains.map(domain=>{const label=document.createElement('label');label.className='domain-option';const checkbox=document.createElement('input');checkbox.type='checkbox';checkbox.checked=state.domainFilters.has(domain.name);checkbox.addEventListener('change',()=>{if(checkbox.checked)state.domainFilters.add(domain.name);else state.domainFilters.delete(domain.name);updateDomainFilterLabel();scheduleFilterLoad();});const name=document.createElement('span');name.className='domain-option-name';name.textContent=domain.name;label.append(checkbox,name,domainStatusBadge(domain));return label;}));}updateDomainFilterLabel();}
