    function renderDomainManager(){if(!$('domain-manager').open)return;const query=$('domain-manager-search').value.trim().toLowerCase();const status=$('domain-manager-filter').value;const domains=state.domains.filter(domain=>(!query||domain.name.toLowerCase().includes(query))&&(!status||domain.status===status));const list=$('domain-manager-list');if(!domains.length){const empty=document.createElement('div');empty.className='permission-row muted';empty.textContent='没有匹配的业务域';list.replaceChildren(empty);}else{list.replaceChildren(...domains.map(domain=>{const row=document.createElement('div');row.className='domain-manager-row';const select=document.createElement('input');select.type='checkbox';select.checked=state.selectedDomains.has(domain.name);select.setAttribute('aria-label','选择 '+domain.name);select.addEventListener('change',()=>{if(select.checked)state.selectedDomains.add(domain.name);else state.selectedDomains.delete(domain.name);renderDomainManagerCount();});const name=document.createElement('div');name.className='domain-manager-name';name.textContent=domain.name;const meta=document.createElement('div');meta.className='muted';meta.textContent=domain.publishedCount+'/'+domain.assetCount+' 项资产已开放';name.append(meta);const toggle=document.createElement('input');toggle.type='checkbox';toggle.checked=domain.status==='open';toggle.indeterminate=domain.status==='partial';toggle.setAttribute('aria-label',(toggle.checked?'关闭 ':'开放 ')+domain.name);toggle.addEventListener('change',async()=>{toggle.disabled=true;await updateDomainsPublished([domain.name],toggle.checked).catch(error=>{alert(error.message);renderDomainManager();});});row.append(select,name,domainStatusBadge(domain),toggle);return row;}));}renderDomainManagerCount();}
