    async function updateDomainsPublished(domains,published){const summaries=state.domains.filter(domain=>domains.includes(domain.name));const affected=summaries.reduce((sum,domain)=>sum+domain.assetCount,0);if(!confirm('确认'+(published?'开放':'关闭')+' '+domains.length+' 个业务域？将影响 '+affected+' 项有效资产。')){renderDomainManager();return;}const result=await api('/admin/api/domains',{method:'PATCH',body:JSON.stringify({platform:state.tab,domains,published})});state.selectedDomains.clear();await loadDomains();await loadAssets();alert('已更新 '+result.updated+' 项资产');}
