    function renderAssetRow(item,index){const row=document.createElement('tr');const select=document.createElement('input');select.type='checkbox';select.checked=state.selected.has(item.asset.id);select.disabled=!item.active;select.setAttribute('aria-label','选择 '+item.asset.title);select.addEventListener('change',()=>{if(select.checked)state.selected.add(item.asset.id);else state.selected.delete(item.asset.id);syncSelectAll();updateBulkActions();});const selectCell=document.createElement('td');selectCell.append(select);const publish=document.createElement('input');publish.type='checkbox';publish.checked=item.published;publish.disabled=!item.active;publish.addEventListener('change',async()=>{publish.disabled=true;try{await api('/admin/api/assets/'+encodeURIComponent(item.asset.id),{method:'PATCH',body:JSON.stringify({published:publish.checked})});item.published=publish.checked;await loadDomains();}catch(error){publish.checked=!publish.checked;alert(error.message);}finally{publish.disabled=!item.active;}});const c0=document.createElement('td');c0.append(publish);const c1=document.createElement('td');c1.className='title';c1.textContent=item.asset.title;const id=document.createElement('div');id.className='muted';id.textContent=item.asset.id;c1.append(id);const cells=[selectCell,c0,c1,textCell(item.asset.type)];if(state.tab==='posthog')cells.push(textCell(postHogAnalysisTypeLabel(item.asset)));cells.push(textCell(item.asset.businessDomain||'—'),statusCell(item.active),textCell(formatDate(item.lastSyncedAt)));const detail=document.createElement('button');detail.className='link-button';detail.textContent='查看';detail.addEventListener('click',()=>openDetail(index));const edit=document.createElement('button');edit.className='link-button';edit.textContent='编辑';edit.addEventListener('click',()=>openEditor(index));const action=document.createElement('td');action.append(detail,edit);cells.push(action);row.append(...cells);return row;}
    async function loadAudit(){const params=new URLSearchParams({user:$('search').value,limit:String(state.limit),offset:String(state.offset)});const data=await api('/admin/api/audit?'+params);state.total=data.total;$('thead').innerHTML='<tr><th>时间</th><th>用户</th><th>客户端</th><th>版本</th><th>工具</th><th>数据问题</th><th>资产</th><th>状态</th><th>行数</th><th>耗时</th></tr>';setupResizableColumns('audit',[190,220,130,100,170,360,260,110,80,110]);$('tbody').replaceChildren(...data.logs.map(log=>{const row=document.createElement('tr');const question=log.dataQuestion||'—';const questionCell=textCell(question);if(log.dataQuestion)questionCell.title=log.dataQuestion;[textCell(formatDate(log.createdAt)),textCell(log.userEmail||'—'),textCell(log.aiClient||'—'),textCell(log.clientVersion||'—'),textCell(log.toolName),questionCell,textCell(log.assetId||'—'),textCell(log.status),textCell(String(log.rowCount??'—')),textCell((log.durationMs??'—')+(log.durationMs===undefined?'':' ms'))].forEach(cell=>row.append(cell));return row;}));updatePager();}
    async function loadTools(){const data=await api('/admin/api/tools');$('global-instructions').value=data.globalInstructions;$('effective-instructions').textContent=data.effectiveInstructions;$('instructions-status').textContent=data.globalInstructions.length+' 个字符';const query=$('search').value.trim().toLowerCase();const tools=data.tools.filter(tool=>!query||[tool.name,tool.title,tool.description,tool.category,tool.usageNotes].join(' ').toLowerCase().includes(query));tools.sort((left,right)=>compareToolValues(left,right,state.toolSort)*(state.toolOrder==='asc'?1:-1));state.total=tools.length;state.items=tools;const page=tools.slice(state.offset,state.offset+state.limit);$('thead').innerHTML='<tr><th class="sortable" data-tool-sort="enabled">开放</th><th class="sortable" data-tool-sort="title">工具</th><th class="sortable" data-tool-sort="category">分类</th><th class="sortable" data-tool-sort="riskLevel">风险</th><th class="sortable" data-tool-sort="description">详情描述</th><th class="sortable" data-tool-sort="updatedAt">更新时间</th><th class="sortable" data-tool-sort="updatedBy">更新人</th><th>操作</th></tr>';bindToolSortHeaders();setupResizableColumns('tools',[82,240,130,90,420,180,200,150]);$('tbody').replaceChildren(...page.map(renderToolRow));updatePager();updateBulkActions();}
    function renderToolRow(tool){const row=document.createElement('tr');const enabled=document.createElement('input');enabled.type='checkbox';enabled.checked=tool.enabled;enabled.setAttribute('aria-label',(tool.enabled?'关闭 ':'开放 ')+tool.name);enabled.addEventListener('change',async()=>{const next=enabled.checked;if(!confirm('确认'+(next?'开放':'关闭')+' MCP 工具 '+tool.name+'？')){enabled.checked=!next;return;}enabled.disabled=true;try{const updated=await api('/admin/api/tools/'+encodeURIComponent(tool.name),{method:'PATCH',body:JSON.stringify({enabled:next})});tool.enabled=updated.enabled;await loadTools();}catch(error){enabled.checked=!next;alert(error.message);}finally{enabled.disabled=false;}});const openCell=document.createElement('td');openCell.append(enabled);const toolCell=document.createElement('td');toolCell.className='title';toolCell.textContent=tool.title;const name=document.createElement('div');name.className='muted';name.textContent=tool.name;toolCell.append(name);const risk=document.createElement('td');const badge=document.createElement('span');badge.className='pill'+(tool.riskLevel==='high'?' off':'');badge.textContent=tool.riskLevel;risk.append(badge);const detail=document.createElement('button');detail.className='link-button';detail.textContent='查看';detail.addEventListener('click',()=>openToolDetail(tool));const action=document.createElement('td');action.append(detail);if(['query_starrocks','export_audience'].includes(tool.name)){const permissions=document.createElement('button');permissions.className='link-button';permissions.textContent='权限设置';permissions.addEventListener('click',()=>openPermissions(tool));action.append(permissions);}row.append(openCell,toolCell,textCell(tool.category),risk,textCell(tool.description),textCell(formatDate(tool.updatedAt)),textCell(tool.updatedBy||'—'),action);return row;}
